using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

// --- Build the chat client with automatic function invocation ---
IChatClient client = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build(services: null!);

// --- Register tools ---
var notebook = new Notebook();
var searcher = new WebSearcher();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(searcher.SearchAsync),
        AIFunctionFactory.Create(notebook.TakeNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// --- Interactive loop ---
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.");

while (true)
{
    Console.Write("\n> ");
    var topic = Console.ReadLine();
    if (topic is null || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;
    if (string.IsNullOrWhiteSpace(topic))
        continue;

    Console.WriteLine($"\n📚 Researching: {topic}\n");

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Your job is to thoroughly research a topic using
            the tools at your disposal, then deliver a clear summary.

            Follow this process:
            1. Search the web 2-3 times with varied queries to gather broad information.
            2. After each search, call TakeNote to record the key findings.
            3. When you have enough material, call GetNotes to review everything.
            4. Write a well-structured summary with sections and key takeaways.

            Always take notes before writing your final summary.
            """),
        new(ChatRole.User, $"Please research the following topic: {topic}"),
    ];

    await foreach (var update in client.GetStreamingResponseAsync(messages, chatOptions))
    {
        Console.Write(update.Text);
    }

    Console.WriteLine();
    notebook.Clear();
}

Console.WriteLine("Goodbye!");

// ---------------------------------------------------------------------------
// Tool: Web Search (DuckDuckGo lite HTML)
// ---------------------------------------------------------------------------
sealed class WebSearcher
{
    private static readonly HttpClient Http = new();

    static WebSearcher()
    {
        Http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        Http.Timeout = TimeSpan.FromSeconds(15);
    }

    [Description("Searches the web for the given query and returns relevant result snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var url = $"https://lite.duckduckgo.com/lite/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);
            return ParseResults(html, query);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    private static string ParseResults(string html, string query)
    {
        var results = new List<string>();

        // DuckDuckGo lite returns snippets in <td class="result-snippet">
        foreach (Match m in Regex.Matches(
            html,
            @"class=""result-snippet""[^>]*>\s*(.*?)\s*</td>",
            RegexOptions.Singleline))
        {
            if (results.Count >= 6) break;
            var text = StripHtml(m.Groups[1].Value);
            if (!string.IsNullOrWhiteSpace(text))
                results.Add(text);
        }

        // Fallback: grab link titles if no snippets found
        if (results.Count == 0)
        {
            foreach (Match m in Regex.Matches(
                html,
                @"<a[^>]+class=""result-link""[^>]*>(.*?)</a>",
                RegexOptions.Singleline))
            {
                if (results.Count >= 6) break;
                var text = StripHtml(m.Groups[1].Value);
                if (!string.IsNullOrWhiteSpace(text))
                    results.Add(text);
            }
        }

        // Second fallback: extract any <td> content that looks substantial
        if (results.Count == 0)
        {
            foreach (Match m in Regex.Matches(
                html,
                @"<td[^>]*>\s*(.{60,}?)\s*</td>",
                RegexOptions.Singleline))
            {
                if (results.Count >= 6) break;
                var text = StripHtml(m.Groups[1].Value);
                if (text.Length > 40)
                    results.Add(text);
            }
        }

        if (results.Count == 0)
            return $"No results found for \"{query}\". Try rephrasing the query.";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for \"{query}\":");
        for (int i = 0; i < results.Count; i++)
            sb.AppendLine($"{i + 1}. {results[i]}");
        return sb.ToString();
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, "<.*?>", " ");
        text = WebUtility.HtmlDecode(text);
        return Regex.Replace(text, @"\s+", " ").Trim();
    }
}

// ---------------------------------------------------------------------------
// Tool: Notebook
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and detailed content. " +
                 "Use this to record key findings from each search.")]
    public string TakeNote(
        [Description("A short descriptive title")] string title,
        [Description("Detailed findings to record")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved. Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        Console.WriteLine($"  📋 Retrieved {_notes.Count} note(s)");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

